def main():
    import sys
    input = sys.stdin.read
    S = list(input().strip())
    n = len(S)
    while True:
        found = False
        i = 0
        while i < n - 1:
            if S[i] == 'W' and S[i+1] == 'A':
                S[i] = 'A'
                S[i+1] = 'C'
                i += 2
                found = True
            else:
                i += 1
        if not found:
            break
    print(''.join(S))

if __name__ == "__main__":
    main()
